INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-07200', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在團體結束階段，工作人員有許多重要的工作任務，「維持和普及化（generalizing）團體改變的成效」 是其中一項，下列關於執行這個工作任務的技巧，何者錯誤？', '["由於成員的問題有很大的差異，工作人員針對某些類型的成員，難以持續維持正向的改變", "工作人員可以運用各種不同情境和環境的設計，協助成員學習新的行為，增加新的能力", "為了增加成員獨自解決問題的能力，當最後一次團體結束時，工作人員就應該結束所有的互動與處遇", "工作人員應協助成員發展對自己解決問題、面對困境等能力的信心，才能有效維持改變的成效"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07201', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「重新建構」意指社會工作者以新的方式幫助案主重新認識自己。案主說：「我覺得自己真是個失敗的 母親，因為太關心孩子，所以太過嚴格的管教他，這樣不僅沒讓孩子成績進步，還讓我們親子關係很疏 離。」請問下列何者不屬於社會工作者「重新建構」的回應？', '["我覺得妳是一個真心關心孩子的母親，雖然教導方式比較不適合孩子，但不致於是個失敗的母親", "妳會覺得自己不是個成功的母親，是因為妳相信妳應該可以用更好的方式來教導孩子，妳覺得目前這 樣的狀態，代表妳管教孩子的方式有問題", "其實一個成功的母親有很多的面向，不只有讓孩子成績進步或是親子關係良好這些方面的表現，妳很 關心孩子，願意檢討自己的錯誤，也是一個成功母親的重要條件", "妳一下子說自己是個失敗的母親，一下又提到自己非常關心孩子，這二者不是很矛盾嗎？我覺得妳要 好好思考自己的行為，重新創造教導孩子的新方法"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07202', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '「社工人員對於案主提出的問題，立基於案主的需要給予必要的協助，而不是依據案主的問題是否值得 協助處理」這段話是社工人員與案主建立專業關係中的那一項原則？', '["非批判的態度", "適度情感表達", "尊重案主自決", "對案主問題予以保密"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "d3e17771926e", "answer_pdf_sha1": "da7bf0f1228e", "source_family": "moex-gov-tw", "moex": {"exam_code": "101130", "c": "902", "s": "0704", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年專技律師會計師不動產估價師專利師民間之公證人考試、第二次社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07203', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有一位中風的長者，在醫院治療復健後，希望出院後能回到家中居住，但他需要有人白天幫他準備餐點 並在需要回院門診時帶他去看醫師，因此社工員幫他連結志工送餐及陪同就醫服務，此時社工員扮演的 角色為：', '["研究者", "評估者", "仲介者", "教育者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07204', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '下列那一項社會工作者在協助非志願性案主過程中的自我表露是不適當的？', '["「當我的小孩還小的時候，我覺得日子很難過！」", "「當我失業的時候，我的生活步調也跟著亂掉了！」", "「五年前我很難適應婚姻破裂的事實！」", "「我目前因婚姻失敗而患了憂鬱症！」"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07205', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '就精神分析觀點而言，下列何者不是其對情感轉移（transference）的描述？', '["情感轉移發生時，是破壞治療關係的開始", "當情感轉移發生時，也可能是治療的起始點", "情感轉移是案主對治療者的內在情緒投射現象", "案主對治療者說：「你像我死去的父親冷酷無情的對我」，是種情感轉移的表現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07206', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當社工員把案主當特定的人來看待而說：「我覺得妳先生對待妳的態度和方式，跟我媽媽的遭遇很類似， 妳好可憐喔！」，這種現象我們稱為專業關係中的：', '["情感轉移", "情感反轉移", "情感依戀", "情感依附錯亂"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07207', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '家庭暴力暨性侵害防治中心的社工師（員）因長期服務受婚姻暴力者，而導致自身惡夢連連且懼怕婚姻 的感同身受現象，稱之為：', '["創傷後壓力症候群", "替代性創傷（vicarious traumatization）", "情感反轉移", "專業崩熬（burnout）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07208', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '社工師（員）表示：「不曉得您有沒有注意到您對您父親有種愛恨交織的情結，一方面渴望父親的關懷 與愛，另一方面卻又抱怨父親對您要求嚴苛。」，此時社工（師）員正在運用何種技巧？', '["自我揭露", "面質", "同理心", "真誠（authenticity）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-07209', 'social-worker', 'social-worker-moex-101-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '當社工師（員）因服務負荷過重而產生精疲力竭、對案主失去服務熱誠或畏懼工作等現象時，稱之為：', '["專業崩熬（burnout）", "情感反轉移", "創傷後壓力症候群", "替代性創傷（vicarious traumatization）"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:37+00:00", "source_pdf_sha1": "639c6a9b062b", "answer_pdf_sha1": "f322bd0dc24c", "source_family": "moex-gov-tw", "moex": {"exam_code": "101030", "c": "902", "s": "0804", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "社會工作直接服務", "year": "101", "exam_name": "101年第一次專技醫師分試中醫師營養師心理師藥師醫事檢驗師護理師護士社會工作師考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
